B.IJ=new A.bJ(B.kz,["Contact Us","Our Contacts","Development","OF APPS","AND WEBSITES","We build apps and websites that highlight you and your company.","Development Stages","Team\nMeeting","App\nDesign","Writing\nCode","App\nLaunch","Don't know where\nto start?","We will develop your app/website from scratch. An intuitive interface with modern design. Our servers are reliably protected, and our solutions are beautiful.","Feedback\n24/7","We strive for excellent customer service and value your opinion. We are always ready to listen to your comments.","Tasks &\nSolutions","We are ready to solve your tasks, regardless of their complexity and scale. Contact us today, and we will help you achieve your goals!","Interface\nDesign","We create attractive\nand intuitive interfaces","Development &\nProgramming","Developers solve problems\nof any complexity","Testing &\nDebugging","We conduct thorough\ntesting of products","Planning &\nAnalysis","We offer the best solution\nfor your business","Our Projects","More About Us","Flutter Development"],t.l)
B.IK=new A.bJ(B.kz,["\u0411\u0430\u0439\u043b\u0430\u043d\u044b\u0448\u0443\u0443","\u0411\u0438\u0437\u0434\u0438\u043d \u0431\u0430\u0439\u043b\u0430\u043d\u044b\u0448\u0442\u0430\u0440","\u0418\u0448\u0442\u0435\u043f \u0447\u044b\u0433\u0443\u0443","\u0422\u0418\u0420\u041a\u0415\u041c\u0415\u041b\u0415\u0420\u0414\u0418\u041d","\u0416\u0410\u041d\u0410 \u0412\u0415\u0411 \u0421\u0410\u0419\u0422\u0422\u0410\u0420\u0414\u042b\u041d","\u0421\u0438\u0437\u0434\u0438 \u0436\u0430\u043d\u0430 \u0441\u0438\u0437\u0434\u0438\u043d \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f\u043d\u044b \u0431\u0430\u0441\u0430 \u0431\u0435\u043b\u0433\u0438\u043b\u0435\u0433\u0435\u043d \u0442\u0438\u0440\u043a\u0435\u043c\u0435\u043b\u0435\u0440 \u0436\u0430\u043d\u0430 \u0432\u0435\u0431-\u0441\u0430\u0439\u0442\u0442\u0430\u0440 \u0436\u0430\u0441\u0430\u0439\u0431\u044b\u0437.","\u0418\u0448\u0442\u0435\u043f \u0447\u044b\u0433\u0443\u0443 \u044d\u0442\u0430\u043f\u0442\u0430\u0440\u044b","\u041a\u043e\u043c\u0430\u043d\u0434\u0430\n\u0436\u044b\u0439\u044b\u043d\u044b","\u0422\u0438\u0440\u043a\u0435\u043c\u0435\n\u0434\u0438\u0437\u0430\u0439\u043d\u044b","\u041a\u043e\u0434\n\u0436\u0430\u0437\u0443\u0443","\u0422\u0438\u0440\u043a\u0435\u043c\u0435\u043d\u0438\n\u0436\u0430\u0440\u044b\u044f\u043b\u043e\u043e","\u041a\u0430\u0439\u0434\u0430\u043d \u0431\u0430\u0448\u0442\u0430\u0440\u044b\u04a3\u044b\u0437\u0434\u044b\n\u0431\u0438\u043b\u0431\u0435\u0439\u0441\u0438\u0437\u0431\u0438?","\u0411\u0438\u0437 \u0442\u0438\u0440\u043a\u0435\u043c\u0435\u043d\u0438/\u0432\u0435\u0431-\u0441\u0430\u0439\u0442\u0442\u044b \u043d\u04e9\u043b\u0434\u04e9\u043d \u0438\u0448\u0442\u0435\u043f \u0447\u044b\u0433\u0430\u0431\u044b\u0437. \u0417\u0430\u043c\u0430\u043d\u0431\u0430\u043f \u0434\u0438\u0437\u0430\u0439\u043d \u043c\u0435\u043d\u0435\u043d \u0438\u043d\u0442\u0443\u0438\u0442\u0438\u0432\u0434\u0438\u043a \u0438\u043d\u0442\u0435\u0440\u0444\u0435\u0439\u0441. \u0421\u0435\u0440\u0432\u0435\u0440\u043b\u0435\u0440\u0438\u0431\u0438\u0437 \u0438\u0448\u0435\u043d\u0438\u043c\u0434\u04af\u04af \u043a\u043e\u0440\u0433\u043e\u043b\u0433\u043e\u043d, \u0447\u0435\u0447\u0438\u043c\u0434\u0435\u0440\u0438\u0431\u0438\u0437 \u0441\u043e\u043d\u0443\u043d.","\u0411\u0430\u0439\u043b\u0430\u043d\u044b\u0448\n24/7","\u0411\u0438\u0437 \u043a\u0430\u0440\u0434\u0430\u0440\u043b\u0430\u0440\u0434\u044b \u043c\u044b\u043a\u0442\u044b \u0442\u0435\u0439\u043b\u04e9\u04e9\u0433\u04e9 \u0443\u043c\u0442\u0443\u043b\u0443\u043f, \u0441\u0438\u0437\u0434\u0438\u043d \u043f\u0438\u043a\u0438\u0440\u0438\u04a3\u0438\u0437\u0434\u0438 \u0431\u0430\u0430\u043b\u0430\u0439\u0431\u044b\u0437. \u0411\u0438\u0437 \u0441\u0438\u0437\u0434\u0438\u043d \u043a\u043e\u043c\u043c\u0435\u043d\u0442\u0430\u0440\u0438\u0439\u043b\u0435\u0440\u0438\u04a3\u0438\u0437\u0434\u0438 \u0443\u0433\u0443\u0443\u0433\u0430 \u0434\u0430\u0439\u044b\u043c\u0430 \u0434\u0430\u044f\u0440\u0431\u044b\u0437.","\u041c\u0430\u0441\u0430\u043b\u0435\u043b\u0435\u0440 \u0436\u0430\u043d\u0430\n\u0447\u0435\u0447\u0438\u043c\u0434\u0435\u0440","\u0411\u0438\u0437 \u0441\u0438\u0437\u0434\u0438\u043d \u043c\u0430\u0441\u0430\u043b\u0430\u043b\u0435\u0440\u0438\u04a3\u0438\u0437\u0434\u0438, \u0430\u043b\u0430\u0440\u0434\u044b\u043d \u0442\u0430\u0442\u0430\u0430\u043b\u0434\u044b\u0433\u044b\u043d\u0430 \u0436\u0430\u043d\u0430 \u043c\u0430\u0441\u0448\u0442\u0430\u0431\u044b\u043d\u0430 \u043a\u0430\u0440\u0430\u0431\u0430\u0441\u0442\u0430\u043d \u0447\u0435\u0447\u04af\u04af\u0433\u04e9 \u0434\u0430\u044f\u0440\u0431\u044b\u0437. \u0411\u0438\u0437\u0433\u0435 \u0431\u04af\u0433\u04af\u043d \u043a\u0430\u0439\u0440\u044b\u043b\u044b\u04a3\u044b\u0437, \u0431\u0438\u0437 \u0441\u0438\u0437\u0433\u0435 \u043c\u0430\u043a\u0441\u0430\u0442\u0442\u0430\u0440\u044b\u04a3\u044b\u0437\u0433\u0430 \u0436\u0435\u0442\u04af\u04af\u0433\u04e9 \u0436\u0430\u0440\u0434\u0430\u043c \u0431\u0435\u0440\u0438\u0431\u0438\u0437!","\u0418\u043d\u0442\u0435\u0440\u0444\u0435\u0439\u0441\n\u0414\u0438\u0437\u0430\u0439\u043d\u044b","\u0416\u0430\u0433\u044b\u043c\u0434\u0443\u0443 \u0436\u0430\u043d\u0430\n\u0442\u04af\u0448\u04af\u043d\u04af\u043a\u0442\u04af\u04af \u0438\u043d\u0442\u0435\u0440\u0444\u0435\u0439\u0441","\u0418\u0448\u0442\u0435\u043f \u0447\u044b\u0433\u0443\u0443 \u0436\u0430\u043d\u0430\n\u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0430\u043b\u043e\u043e","\u0418\u0448\u0442\u0435\u043f \u0447\u044b\u0433\u0443\u0443\u0447\u0443\u043b\u0430\u0440 \u043a\u0430\u0430\u043b\u0430\u0433\u0430\u043d\n\u0442\u0430\u0442\u0430\u0430\u043b\u0434\u044b\u043a\u0442\u0430\u0433\u044b \u043c\u0430\u0441\u0435\u043b\u0435\u043d\u0438 \u0447\u0435\u0447\u0435\u0442","\u0422\u0435\u0441\u0442\u0438\u0440\u043b\u04e9\u04e9 \u0436\u0430\u043d\u0430\n\u043e\u04a3\u0434\u043e\u043e","\u041f\u0440\u043e\u0434\u0443\u043a\u0442\u0442\u0430\u0440\u0434\u044b \u0442\u0449\u0430\u0442\u0435\u043b\u044c\u043d\u043e\n\u0442\u0435\u0441\u0442\u0438\u0440\u043b\u0435\u0439\u0431\u0438\u0437","\u041f\u043b\u0430\u043d\u0434\u043e\u043e \u0436\u0430\u043d\u0430\n\u0410\u043d\u0430\u043b\u0438\u0437","\u0411\u0438\u0437\u043d\u0435\u0441\u0438\u04a3\u0438\u0437 \u04af\u0447\u04af\u043d\n\u043c\u044b\u043a\u0442\u044b \u0447\u0435\u0447\u0438\u043c \u0441\u0443\u043d\u0443\u0448\u0442\u0430\u0439\u0431\u044b\u0437","\u0411\u0438\u0437\u0434\u0438\u043d \u0434\u043e\u043b\u0431\u043e\u043e\u0440\u043b\u043e\u0440","\u0411\u0438\u0437 \u0436\u04e9\u043d\u04af\u043d\u0434\u04e9 \u0434\u0430\u0433\u044b","Flutter \u0418\u0448\u0442\u0435\u043f \u0447\u044b\u0433\u0443\u0443"],t.l)
